SP_AlterWorkLoadGroup:
CREATE PROC [DWH_dbo].[SP_AlterWorkLoadGroup] @group_name [VARCHAR](100),@min_percentage_resource [INT],@cap_percentage_resource [INT],@request_min_resource_grant_percent [INT],@request_max_resource_grant_percent [INT],@importance [VARCHAR](50),@query_execution_timeout_sec [INT] AS
BEGIN 

    DECLARE @alter VARCHAR(MAX)

    SELECT @alter= CONCAT(
       'ALTER WORKLOAD GROUP [',
       @group_name,
       '] WITH (', 
               CASE WHEN @min_percentage_resource IS NOT NULL THEN 'MIN_PERCENTAGE_RESOURCE = ' END,
               @min_percentage_resource  ,
               CASE WHEN @cap_percentage_resource IS NOT NULL THEN ' ,CAP_PERCENTAGE_RESOURCE = ' END ,
               @cap_percentage_resource,
               CASE WHEN @request_min_resource_grant_percent IS NOT NULL THEN ' ,REQUEST_MIN_RESOURCE_GRANT_PERCENT = ' END,
               @request_min_resource_grant_percent,
               CASE WHEN @request_max_resource_grant_percent IS NOT NULL THEN ' ,REQUEST_MAX_RESOURCE_GRANT_PERCENT = ' END,
               @request_max_resource_grant_percent,
               CASE WHEN @importance IS NOT NULL THEN ' ,IMPORTANCE =' END,
               @importance,
               CASE WHEN @query_execution_timeout_sec IS NOT NULL THEN ' ,QUERY_EXECUTION_TIMEOUT_SEC =' END,
               @query_execution_timeout_sec,
       ' )'
       )


	

      EXEC (@alter)
      --PRINT @alter
END

SP_Dim_Instrument_Correlation_ByGroupRan:
CREATE PROC [DWH_dbo].[SP_Dim_Instrument_Correlation_ByGroupRange] @Date [Date],@TableID [int],@MinGroupID [int],@MaxGroupID [INT] AS
BEGIN
 	   SET NOCOUNT ON;

    BEGIN TRY
        -- Run the first call with IsInitial = 1
        EXEC DWH_dbo.SP_Dim_Instrument_Correlation_FilterByInstrumentID 
            @Date, 
            @MinGroupID, 
            @TableID, 
            1; --Need Delete

        -- Increment group ID for the loop
        SET @MinGroupID = @MinGroupID + 1;

        -- Loop through remaining group IDs with IsInitial = 0
        WHILE @MinGroupID <= @MaxGroupID
        BEGIN
            EXEC DWH_dbo.SP_Dim_Instrument_Correlation_FilterByInstrumentID 
                @Date, 
                @MinGroupID, 
                @TableID, 
                0; --Not Need Delete

            SET @MinGroupID = @MinGroupID + 1;
        END
    END TRY
    BEGIN CATCH
        -- Capture and re-raise detailed error if something fails
        DECLARE @ErrorMessage NVARCHAR(4000) = ERROR_MESSAGE();
        DECLARE @ErrorSeverity INT = ERROR_SEVERITY();
        DECLARE @ErrorState INT = ERROR_STATE();

        RAISERROR('Error in Run_InstrumentCorrelation_ByGroupRange: %s', 
                  @ErrorSeverity, @ErrorState, @ErrorMessage);
    END CATCH
end
